// Provide operator delete so vtables generated by `virtual ~HemisphereApplet()`
// resolve at link time. The shim never deletes via vtable (applets are
// constructed via placement-new in a fixed sram slot and destroyed via
// explicit ~HemisphereApplet() in hemispheres_swap), so this is unreachable
// in practice. NT firmware does not provide operator delete.
void operator delete(void*) noexcept {}
void operator delete(void*, std::size_t) noexcept {}
void operator delete[](void*) noexcept {}
void operator delete[](void*, std::size_t) noexcept {}

