void HS::IOFrame::ClockOut(DAC_CHANNEL ch, int pulselength) {
    if (pulselength <= 0) pulselength = HEMISPHERE_CLOCK_TICKS;
    outputs[ch].set(PULSE_VOLTAGE * ONE_OCTAVE);
    clock_countdown[ch] = pulselength;
}

